/**
 * @suppress
 */
public object FfiConverterTypeFfiNode: FfiConverter<FfiNode, Pointer> {

    override fun lower(value: FfiNode): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): FfiNode {
        return FfiNode(value)
    }

    override fun read(buf: ByteBuffer): FfiNode {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: FfiNode) = 8UL

    override fun write(value: FfiNode, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



/**
 * Identity bundle returned from `generate_identity()`.
 *
 * **SECURITY WARNING**: The `secret_key_hex` contains sensitive key material.
 * Store it securely using platform keychain/keystore APIs:
 * - Android: Use `EncryptedSharedPreferences` or `Keystore`
 * - iOS: Use `Keychain Services`
 *
 * Do not log, transmit, or store in plain text.
 */
data class IdentityBundle (
    /**
     * Secret key (64 hex chars = 32 bytes). Keep this secure!
     */
    var `secretKeyHex`: kotlin.String, 
    /**
     * Public identity (64 hex chars = 32 bytes). Safe to share.
     */
    var `identityHex`: kotlin.String, 
    /**
     * `PoW` nonce (16 hex chars = 8 bytes). Required to recreate node.
     */
    var `nonceHex`: kotlin.String
) {
    
    companion object
}

