 */
public object FfiConverterTypeIdentityBundle: FfiConverterRustBuffer<IdentityBundle> {
    override fun read(buf: ByteBuffer): IdentityBundle {
        return IdentityBundle(
            FfiConverterString.read(buf),
            FfiConverterString.read(buf),
            FfiConverterString.read(buf),
        )
    }

    override fun allocationSize(value: IdentityBundle) = (
            FfiConverterString.allocationSize(value.`secretKeyHex`) +
            FfiConverterString.allocationSize(value.`identityHex`) +
            FfiConverterString.allocationSize(value.`nonceHex`)
    )

    override fun write(value: IdentityBundle, buf: ByteBuffer) {
            FfiConverterString.write(value.`secretKeyHex`, buf)
            FfiConverterString.write(value.`identityHex`, buf)
            FfiConverterString.write(value.`nonceHex`, buf)
