/**
 * FFI-safe error type.
 *
 * All Korium operations that can fail return this error type.
 * Use the error message for debugging; the variant indicates the category.
 */
sealed class KoriumException: kotlin.Exception() {
    
    class InvalidAddress(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class InvalidIdentity(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class InvalidKey(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class ConnectionFailed(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class Timeout(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class NotConnected(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class AlreadySubscribed(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class NotSubscribed(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class ChannelClosed(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class PowFailed(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class NotFound(
        ) : KoriumException() {
        override val message
            get() = ""
    }
    
    class Internal(
        
        val `msg`: kotlin.String
        ) : KoriumException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<KoriumException> {
        override fun lift(error_buf: RustBuffer.ByValue): KoriumException = FfiConverterTypeKoriumError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeKoriumError : FfiConverterRustBuffer<KoriumException> {
    override fun read(buf: ByteBuffer): KoriumException {
        

        return when(buf.getInt()) {
            1 -> KoriumException.InvalidAddress()
            2 -> KoriumException.InvalidIdentity()
            3 -> KoriumException.InvalidKey()
            4 -> KoriumException.ConnectionFailed()
            5 -> KoriumException.Timeout()
            6 -> KoriumException.NotConnected()
            7 -> KoriumException.AlreadySubscribed()
            8 -> KoriumException.NotSubscribed()
            9 -> KoriumException.ChannelClosed()
            10 -> KoriumException.PowFailed()
            11 -> KoriumException.NotFound()
            12 -> KoriumException.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: KoriumException): ULong {
        return when(value) {
            is KoriumException.InvalidAddress -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.InvalidIdentity -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.InvalidKey -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.ConnectionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.Timeout -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.NotConnected -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.AlreadySubscribed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.NotSubscribed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.ChannelClosed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.PowFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is KoriumException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
        }
    }

    override fun write(value: KoriumException, buf: ByteBuffer) {
        when(value) {
            is KoriumException.InvalidAddress -> {
                buf.putInt(1)
                Unit
            }
            is KoriumException.InvalidIdentity -> {
                buf.putInt(2)
                Unit
            }
            is KoriumException.InvalidKey -> {
                buf.putInt(3)
                Unit
            }
            is KoriumException.ConnectionFailed -> {
                buf.putInt(4)
                Unit
            }
            is KoriumException.Timeout -> {
                buf.putInt(5)
                Unit
            }
            is KoriumException.NotConnected -> {
                buf.putInt(6)
                Unit
            }
            is KoriumException.AlreadySubscribed -> {
                buf.putInt(7)
                Unit
            }
            is KoriumException.NotSubscribed -> {
                buf.putInt(8)
                Unit
            }
            is KoriumException.ChannelClosed -> {
                buf.putInt(9)
                Unit
            }
            is KoriumException.PowFailed -> {
                buf.putInt(10)
                Unit
            }
            is KoriumException.NotFound -> {
                buf.putInt(11)
                Unit
            }
            is KoriumException.Internal -> {
                buf.putInt(12)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalByteArray: FfiConverterRustBuffer<kotlin.ByteArray?> {
    override fun read(buf: ByteBuffer): kotlin.ByteArray? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterByteArray.read(buf)
    }

    override fun allocationSize(value: kotlin.ByteArray?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterByteArray.allocationSize(value)
        }
    }

    override fun write(value: kotlin.ByteArray?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterByteArray.write(value, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterOptionalTypeFfiBidirectionalStream: FfiConverterRustBuffer<FfiBidirectionalStream?> {
    override fun read(buf: ByteBuffer): FfiBidirectionalStream? {
