        } else {
            return 1UL + FfiConverterTypeFfiBidirectionalStream.allocationSize(value)
        }
    }

    override fun write(value: FfiBidirectionalStream?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
